CREATE DATABASE IF NOT EXISTS saraswati_library CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
USE saraswati_library;
CREATE TABLE users (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, full_name VARCHAR(120) NOT NULL, email VARCHAR(160) NOT NULL UNIQUE, mobile VARCHAR(20) NOT NULL, password_hash VARCHAR(255) NOT NULL, profile_image VARCHAR(255), role ENUM('student','admin') NOT NULL DEFAULT 'student', status ENUM('active','suspended','deleted') NOT NULL DEFAULT 'active', created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP);
CREATE TABLE admins (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, user_id BIGINT UNSIGNED NOT NULL, permissions JSON, FOREIGN KEY (user_id) REFERENCES users(id));
CREATE TABLE books (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, book_code VARCHAR(40) UNIQUE, book_name VARCHAR(180) NOT NULL, author VARCHAR(120), category VARCHAR(80), isbn VARCHAR(32), quantity INT NOT NULL DEFAULT 1, available_copies INT NOT NULL DEFAULT 1, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE book_issues (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, book_id BIGINT UNSIGNED NOT NULL, user_id BIGINT UNSIGNED NOT NULL, issue_date DATE NOT NULL, return_date DATE, actual_return_date DATE, fine_amount DECIMAL(10,2) DEFAULT 0, status ENUM('issued','returned','overdue') DEFAULT 'issued', FOREIGN KEY(book_id) REFERENCES books(id), FOREIGN KEY(user_id) REFERENCES users(id));
CREATE TABLE seats (id INT UNSIGNED AUTO_INCREMENT PRIMARY KEY, seat_number INT NOT NULL UNIQUE, status ENUM('available','reserved','occupied','maintenance') DEFAULT 'available');
CREATE TABLE seat_bookings (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, seat_id INT UNSIGNED NOT NULL, user_id BIGINT UNSIGNED NOT NULL, start_time DATETIME, end_time DATETIME, status ENUM('reserved','occupied','completed','cancelled') DEFAULT 'reserved', FOREIGN KEY(seat_id) REFERENCES seats(id), FOREIGN KEY(user_id) REFERENCES users(id));
CREATE TABLE waiting_queue (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, user_id BIGINT UNSIGNED NOT NULL, requested_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, status ENUM('waiting','allocated','cancelled') DEFAULT 'waiting', priority INT DEFAULT 0, FOREIGN KEY(user_id) REFERENCES users(id));
CREATE TABLE attendance (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, user_id BIGINT UNSIGNED NOT NULL, seat_id INT UNSIGNED, check_in DATETIME NOT NULL, check_out DATETIME, total_minutes INT DEFAULT 0, qr_token VARCHAR(120), FOREIGN KEY(user_id) REFERENCES users(id), FOREIGN KEY(seat_id) REFERENCES seats(id));
CREATE TABLE membership_plans (id INT UNSIGNED AUTO_INCREMENT PRIMARY KEY, name VARCHAR(80) NOT NULL, duration_days INT NOT NULL, price DECIMAL(10,2) NOT NULL, features JSON);
CREATE TABLE subscriptions (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, user_id BIGINT UNSIGNED NOT NULL, plan_id INT UNSIGNED NOT NULL, starts_on DATE NOT NULL, expires_on DATE NOT NULL, status ENUM('active','expired','cancelled') DEFAULT 'active', FOREIGN KEY(user_id) REFERENCES users(id), FOREIGN KEY(plan_id) REFERENCES membership_plans(id));
CREATE TABLE payments (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, user_id BIGINT UNSIGNED NOT NULL, subscription_id BIGINT UNSIGNED, amount DECIMAL(10,2) NOT NULL, gst DECIMAL(10,2) DEFAULT 0, final_amount DECIMAL(10,2) NOT NULL, transaction_id VARCHAR(120) UNIQUE, status ENUM('pending','approved','rejected') DEFAULT 'pending', paid_at DATETIME, FOREIGN KEY(user_id) REFERENCES users(id));
CREATE TABLE email_logs (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, user_id BIGINT UNSIGNED, subject VARCHAR(180), recipient VARCHAR(180), status VARCHAR(40), sent_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE settings (id INT UNSIGNED AUTO_INCREMENT PRIMARY KEY, setting_key VARCHAR(100) UNIQUE, setting_value TEXT);
CREATE TABLE notifications (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, user_id BIGINT UNSIGNED, title VARCHAR(160), body TEXT, read_at DATETIME, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE activity_logs (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, user_id BIGINT UNSIGNED, action VARCHAR(120), metadata JSON, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
